```c
#include <stdio.h>

int main() {
    int c, a, b;
    scanf("%d %d %d", &c, &a, &b);
    int level = 0;
    while (c != 1) {
        level++;
        c /= 2;
    }
    a--;
    b--;
    int roundik = 0;
    while (a != b) {
        roundik++;
        a /= 2;
        b /= 2;
    }
    if (roundik == level) {
        printf("Final!\n");
    } else {
        printf("%d\n", roundik);
    }
    return 0;
}
